$pgv_lang["SHOW_MULTISITE_SEARCH_help"]	= "~#pgv_lang[SHOW_MULTISITE_SEARCH]#~<br /><br />La recerca a mĂşltiples llocs permet als usuaris cercar entre les mĂşltiples pĂ gines web PhpGedView que hagueu configurat a l'Ă rea d'administraciĂł de GestiĂł de Llocs o enllaĂ§at remotament. Aquesta opciĂł controla si la recerca a mĂşltiples llocs Ă©s accessible a tothom o solament als amb accĂ©s.";
$pgv_lang["SHOW_MULTISITE_SEARCH"]		= "Mostra cercar a mĂşltiples llocs";
