$pgv_lang["META_ROBOTS"]		= "METAetiqueta de robots";
$pgv_lang["META_ROBOTS_help"]	= "~#pgv_lang[META_ROBOTS]#~<br /><br />El contingut a posar al la meta-etiqueta de robots a la capĂ§alera de la pĂ gina HTML. Alguns robots o motors de recerca web ignoren aquest contingut.";
$pgv_lang["META_REVISIT"]		= "FreqĂĽĂ¨ncia amb que els motors de recerca tornaran a visitar les METAetiquetes";
