$pgv_lang["ged_filter_description_help"] = "~#pgv_lang[ged_filter_description]#~<br /><br />Aquesta opciĂł us permet localitzar text associat a opcions de configuraciĂł.<br /><br />Si hi entreu lletres, la recerca intentarĂ  localitzar totes les opcions de configuraciĂł que contingui aquesta seqĂĽĂ¨ncia de lletres. La recerca esdevĂ© mĂ©s precisa si hi entreu mĂ©s carĂ cters.";

